package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class CSVFormatWithHeaderTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testWithHeader_NullMetaData_ReturnsSameFormatWithNullHeader() throws SQLException {
        // Explicit cast to ResultSetMetaData to resolve ambiguity
        CSVFormat result = csvFormat.withHeader((ResultSetMetaData) null);
        assertNotNull(result);
        assertNull(result.getHeader());
    }

    @Test
    public void testWithHeader_EmptyMetaData_ReturnsFormatWithEmptyHeader() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenReturn(0);

        CSVFormat result = csvFormat.withHeader(metaData);
        assertNotNull(result);
        assertNotNull(result.getHeader());
        assertEquals(0, result.getHeader().length);
    }

    @Test
    public void testWithHeader_MetaDataWithMultipleColumns_ReturnsFormatWithHeaders() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenReturn(3);
        when(metaData.getColumnLabel(1)).thenReturn("col1");
        when(metaData.getColumnLabel(2)).thenReturn("col2");
        when(metaData.getColumnLabel(3)).thenReturn("col3");

        CSVFormat result = csvFormat.withHeader(metaData);
        assertNotNull(result);
        String[] headers = result.getHeader();
        assertNotNull(headers);
        assertEquals(3, headers.length);
        assertEquals("col1", headers[0]);
        assertEquals("col2", headers[1]);
        assertEquals("col3", headers[2]);
    }

    @Test
    public void testWithHeader_MetaDataThrowsSQLException_PropagatesException() throws SQLException {
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(metaData.getColumnCount()).thenThrow(new SQLException("Test exception"));

        assertThrows(SQLException.class, () -> csvFormat.withHeader(metaData));
    }
}
